"use client";
import { logger } from "@/lib/logger";

import { useEffect, useRef, useState } from "react";
import { io, Socket } from "socket.io-client";
import type { LatentState, ListenerStatus, PeerMapEntry } from "@/lib/types";
import { ICE_SERVERS } from "@/lib/types";
import { useNetworkTelemetry } from "./useNetworkTelemetry";
import { eventBus } from "@/lib/eventBus";

export function useListener() {
  const [status, setStatus] = useState<ListenerStatus>("AMBIENT");
  const [activePeers, setActivePeers] = useState<number>(0);
  const [globalPeerMap, setGlobalPeerMap] = useState<PeerMapEntry[]>([]);
  const [socketId, setSocketId] = useState<string | null>(null);
  const [audioStream, setAudioStream] = useState<MediaStream | null>(null);
  const [upstreamTargetId, setUpstreamTargetId] = useState<string | null>(null);
  const socketRef = useRef<Socket | null>(null);
  const statusRef = useRef(status);
  const lastReportedLatentRef = useRef<LatentState | null>(null);
  const upstreamTargetIdRef = useRef<string | null>(null);
  const upstreamPcRef = useRef<RTCPeerConnection | null>(null);
  const pendingUpstreamPcRef = useRef<RTCPeerConnection | null>(null);
  const downstreamPcsRef = useRef<Map<string, RTCPeerConnection>>(new Map());
  const audioElementRef = useRef<HTMLAudioElement | null>(null);
  const reconnectAttemptsRef = useRef<number>(0);

  const { dataTransferRate } = useNetworkTelemetry(upstreamPcRef, status);

  useEffect(() => {
    statusRef.current = status;
  }, [status]);

  useEffect(() => {
    const audio = new Audio();
    audio.autoplay = true;
    audio.muted = true; // MUST be muted so the browser doesn't play raw audio bypassing WebAudio API
    audioElementRef.current = audio;
    return () => stopListening();
  }, []);

  const createUpstreamConnection = (
    targetId: string,
    socket: Socket,
  ): RTCPeerConnection => {
    const pc = new RTCPeerConnection({
      iceServers: ICE_SERVERS,
    });

    pc.onicecandidate = (event) => {
      if (event.candidate) {
        socket.emit("signal", {
          target: targetId,
          signal: { type: "candidate", candidate: event.candidate },
        });
      }
    };

    pc.ontrack = (event) => {
      logger.info("P2P-Listener", "[PC] Upstream track received from:", targetId);

      if (pendingUpstreamPcRef.current === pc && upstreamPcRef.current) {
        logger.info("P2P-Listener", "[PC] Hot-swap complete. Closing old connection.");
        upstreamPcRef.current.close();
        upstreamPcRef.current = pc;
        pendingUpstreamPcRef.current = null;
      } else if (!upstreamPcRef.current) {
        upstreamPcRef.current = pc;
      }

      // Reset backoff counter on successful connection
      reconnectAttemptsRef.current = 0;

      upstreamTargetIdRef.current = targetId;
      setUpstreamTargetId(targetId);

      // Relay Logic: Forward this new track to all existing downstream children
      if (event.streams[0]) {
        const stream = event.streams[0];
        downstreamPcsRef.current.forEach((childPc) => {
          const senders = childPc.getSenders();
          stream.getTracks().forEach((track) => {
            const existingSender = senders.find(s => s.track?.kind === track.kind);
            if (existingSender) {
              existingSender.replaceTrack(track).catch(e => console.warn("Failed to replace relay track", e));
            } else {
              childPc.addTrack(track, stream);
            }
          });
        });
      }

      if (audioElementRef.current && event.streams[0]) {
        // Always update the stream source — ambient reconnections need this
        audioElementRef.current.srcObject = event.streams[0];
        setAudioStream(event.streams[0]);
        // Only upgrade to LISTENING if they actively clicked it;
        // otherwise, stay AMBIENT and let spatial audio map the drone
        if (statusRef.current === "CONNECTING") {
          setStatus("LISTENING");
          if (socketRef.current?.id) {
            eventBus.emit('listener_joined', { nodeId: socketRef.current.id, channelId: targetId });
          }
        }
      }
    };

    pc.onconnectionstatechange = () => {
      if (
        pc.connectionState === "disconnected" ||
        pc.connectionState === "failed"
      ) {
        logger.info("P2P-Listener", "[PC] Upstream disconnected. Requesting new parent...");
        pc.close();

        if (socketRef.current?.id) {
          eventBus.emit('listener_left', { nodeId: socketRef.current.id });
        }

        if (upstreamPcRef.current === pc) {
          upstreamPcRef.current = null;
          upstreamTargetIdRef.current = null;
          setUpstreamTargetId(null);
          if (statusRef.current === "LISTENING") {
            setStatus("CONNECTING");
          }
          if (audioElementRef.current) audioElementRef.current.srcObject = null;
          setAudioStream(null);

          if (socket.connected) {
            const currentLatent =
              statusRef.current === "LISTENING" ||
                statusRef.current === "CONNECTING"
                ? (audioElementRef.current as any)?.latentData || { x: 0, y: 0, spin: 0 }
                : { x: 0, y: 0, spin: 0 };

            // Exponential Backoff with Jitter
            const attempts = reconnectAttemptsRef.current;
            const backoffMs = Math.min(10000, Math.pow(2, attempts) * 1000) + Math.random() * 500;
            reconnectAttemptsRef.current += 1;

            logger.info("P2P-Listener", `[Backoff] Reconnecting to mesh in ${Math.round(backoffMs)}ms... (Attempt ${attempts + 1})`);
            setTimeout(() => {
              // Ensure socket is still connected after timeout
              if (socketRef.current && socketRef.current.connected) {
                requestUpstreamPeer(socketRef.current, currentLatent);
              }
            }, backoffMs);
          }
        } else if (pendingUpstreamPcRef.current === pc) {
          pendingUpstreamPcRef.current = null;
        }
      }
    };

    if (!upstreamPcRef.current && !pendingUpstreamPcRef.current) {
      upstreamPcRef.current = pc;
    }

    return pc;
  };

  const createDownstreamConnection = (
    targetId: string,
    stream: MediaStream | null,
    socket: Socket,
  ): RTCPeerConnection => {
    const pc = new RTCPeerConnection({
      iceServers: ICE_SERVERS,
    });

    pc.onicecandidate = (event) => {
      if (event.candidate) {
        socket.emit("signal", {
          target: targetId,
          signal: { type: "candidate", candidate: event.candidate },
        });
      }
    };

    if (stream) {
      stream.getTracks().forEach((track) => pc.addTrack(track, stream));
    }

    pc.onconnectionstatechange = () => {
      logger.info("P2P-Listener",
        `[PC] Downstream child state (${targetId}):`,
        pc.connectionState,
      );
      if (
        pc.connectionState === "disconnected" ||
        pc.connectionState === "failed"
      ) {
        pc.close();
        downstreamPcsRef.current.delete(targetId);
        setActivePeers(downstreamPcsRef.current.size);
      }
    };

    downstreamPcsRef.current.set(targetId, pc);
    setActivePeers(downstreamPcsRef.current.size);
    return pc;
  };

  const audioStreamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    audioStreamRef.current = audioStream;
  }, [audioStream]);

  // Connect to Tracker immediately for observing the Topology Field
  useEffect(() => {
    const socket = io();
    socketRef.current = socket;

    const latentPayload = {
      x: Math.random() * window.innerWidth,
      y: Math.random() * window.innerHeight,
      spin: Math.random(),
    };
    lastReportedLatentRef.current = { ...latentPayload };

    socket.on("connect", () => {
      logger.info("P2P-Listener",
        "Connected to Tracker as Observer. Requesting ambient WebRTC connection.",
      );
      setSocketId(socket.id || null);
      requestUpstreamPeer(socket, latentPayload);
    });

    socket.on("peer_map_update", (peers: PeerMapEntry[]) => {
      setGlobalPeerMap(peers);
      setActivePeers(Math.max(0, peers.length - 1)); // We exclude ourselves
    });

    socket.on(
      "reconnect_suggestion",
      async (data: { targetPeer: { id: string } }) => {
        if (statusRef.current !== "LISTENING" || pendingUpstreamPcRef.current)
          return;
        logger.info("P2P-Listener",
          `[Re-Route] Tracker suggested better adjacent peer: ${data.targetPeer.id}. Hot-swapping...`,
        );
        const swapPc = createUpstreamConnection(data.targetPeer.id, socket);
        pendingUpstreamPcRef.current = swapPc;
        const offer = await swapPc.createOffer({
          offerToReceiveAudio: true,
          offerToReceiveVideo: false,
        });
        await swapPc.setLocalDescription(offer);
        socket.emit("signal", { target: data.targetPeer.id, signal: offer });
      },
    );

    socket.on(
      "signal",
      async (data: {
        sender: string;
        signal: RTCSessionDescriptionInit | RTCIceCandidateInit;
      }) => {
        const { sender, signal } = data;

        if ("type" in signal && signal.type === "answer" && upstreamPcRef.current) {
          if (upstreamPcRef.current.signalingState === "have-local-offer") {
            await upstreamPcRef.current
              .setRemoteDescription(new RTCSessionDescription(signal as RTCSessionDescriptionInit))
              .catch((e) => console.warn("Failed to set remote answer:", e));
          } else {
            console.warn(
              `[PC] Ignored answer because signalingState is ${upstreamPcRef.current.signalingState}`,
            );
          }
        } else if ("type" in signal && signal.type === "offer") {
          const currentStream = audioStreamRef.current;
          // RELAY CHANGE: We don't reject if stream is null.
          // We accept the connection, and when our upstream provides the stream,
          // we will push the tracks to this child in `pc.ontrack`.

          let childPc = downstreamPcsRef.current.get(sender);
          if (!childPc)
            childPc = createDownstreamConnection(sender, currentStream, socket);

          await childPc.setRemoteDescription(new RTCSessionDescription(signal as RTCSessionDescriptionInit));
          const answer = await childPc.createAnswer();
          await childPc.setLocalDescription(answer);
          socket.emit("signal", { target: sender, signal: answer });
        } else if ("candidate" in signal) {
          if (upstreamPcRef.current && upstreamPcRef.current.remoteDescription) {
            await upstreamPcRef.current
              .addIceCandidate(new RTCIceCandidate(signal as RTCIceCandidateInit))
              .catch((e) => console.warn(e));
          }
          const childPc = downstreamPcsRef.current.get(sender);
          if (childPc && childPc.remoteDescription) {
            await childPc
              .addIceCandidate(new RTCIceCandidate(signal as RTCIceCandidateInit))
              .catch((e) => console.warn(e));
          }
        }
      });

    socket.on("broadcast_started", () => {
      // The Tracker will emit a map update soon anyway, which might trigger a re-route.
      // We can actively poll for a peer if we don't have one.
      if (!upstreamPcRef.current) {
        const currentLatent = lastReportedLatentRef.current || {
          x: Math.random() * window.innerWidth,
          y: Math.random() * window.innerHeight,
          spin: Math.random(),
        };
        requestUpstreamPeer(socket, currentLatent);
      }
    });

    socket.on("disconnect", () => {
      if (statusRef.current === "LISTENING") {
        setStatus("CONNECTING");
      }
      setAudioStream(null);
      if (audioElementRef.current) audioElementRef.current.srcObject = null;
    });

    const handleLatentUpdate = (e: CustomEvent) => {
      if (!socket.connected) return;
      const newState = e.detail;
      const oldState = lastReportedLatentRef.current;

      if (oldState) {
        const distSq =
          Math.pow(newState.x - oldState.x, 2) +
          Math.pow(newState.y - oldState.y, 2);
        const spinDiff = Math.abs(newState.spin - oldState.spin);

        if (distSq > 2500 || spinDiff > 0.05) {
          socket.emit("report_state", {
            latentState: newState,
            activeConnections: downstreamPcsRef.current.size,
            currentUpstreamId: upstreamTargetIdRef.current,
          });
          lastReportedLatentRef.current = { ...newState };
        }
      } else {
        socket.emit("report_state", {
          latentState: newState,
          activeConnections: downstreamPcsRef.current.size,
          currentUpstreamId: upstreamTargetIdRef.current,
        });
        lastReportedLatentRef.current = { ...newState };
      }
    };

    window.addEventListener(
      "resonance_latent_update",
      handleLatentUpdate as EventListener,
    );

    return () => {
      socket.disconnect();
      window.removeEventListener(
        "resonance_latent_update",
        handleLatentUpdate as EventListener,
      );
    };
  }, []);

  const requestUpstreamPeer = (
    socket: Socket,
    latentState: { x: number; y: number; spin: number },
  ) => {
    socket.emit(
      "request_peers",
      { latentState },
      async (res: { peers: { id: string; role: string; score: number }[] }) => {
        if (res.peers && res.peers.length > 0) {
          const targetPeer = res.peers[0];
          if (!upstreamPcRef.current) {
            upstreamTargetIdRef.current = targetPeer.id;
            setUpstreamTargetId(targetPeer.id);
            const pc = createUpstreamConnection(targetPeer.id, socket);
            upstreamPcRef.current = pc;
            const offer = await pc.createOffer({
              offerToReceiveAudio: true,
              offerToReceiveVideo: false,
            });
            await pc.setLocalDescription(offer);

            eventBus.emit('relay_selected', { parentNodeId: targetPeer.id });

            socket.emit("signal", { target: targetPeer.id, signal: offer });
          }
        } else {
          logger.info("P2P-Listener", "No active broadcasts or network saturated.");
          setStatus("AMBIENT");
        }
      },
    );
  };

  const startListening = async (targetNodeId?: string) => {
    if (status === "LISTENING" && upstreamTargetIdRef.current === targetNodeId)
      return;

    if (targetNodeId && socketRef.current && socketRef.current.connected) {
      logger.info("P2P-Listener", `Explicitly tuning into broadcast: ${targetNodeId}`);
      if (
        upstreamPcRef.current &&
        upstreamTargetIdRef.current === targetNodeId
      ) {
        // Already connected to this peer (e.g. returning from ambient) — just re-tune
        setUpstreamTargetId(targetNodeId);
      } else if (
        upstreamPcRef.current &&
        upstreamTargetIdRef.current !== targetNodeId
      ) {
        // Hot swap to new broadcast
        const swapPc = createUpstreamConnection(
          targetNodeId,
          socketRef.current,
        );
        pendingUpstreamPcRef.current = swapPc;
        const offer = await swapPc.createOffer({
          offerToReceiveAudio: true,
          offerToReceiveVideo: false,
        });
        await swapPc.setLocalDescription(offer);
        socketRef.current.emit("signal", {
          target: targetNodeId,
          signal: offer,
        });
      } else if (!upstreamPcRef.current) {
        // Direct specific connection
        upstreamTargetIdRef.current = targetNodeId;
        setUpstreamTargetId(targetNodeId);
        const pc = createUpstreamConnection(targetNodeId, socketRef.current);
        upstreamPcRef.current = pc;
        const offer = await pc.createOffer({
          offerToReceiveAudio: true,
          offerToReceiveVideo: false,
        });
        await pc.setLocalDescription(offer);
        socketRef.current.emit("signal", {
          target: targetNodeId,
          signal: offer,
        });
      }
      setStatus("LISTENING");
    } else if (!targetNodeId) {
      // Auto ambient logic
      if (!upstreamPcRef.current) {
        setStatus("CONNECTING");
        const latentPayload = lastReportedLatentRef.current || {
          x: Math.random() * window.innerWidth,
          y: Math.random() * window.innerHeight,
          spin: Math.random(),
        };
        if (socketRef.current && socketRef.current.connected) {
          requestUpstreamPeer(socketRef.current, latentPayload);
        }
      } else {
        setStatus("LISTENING");
      }
    }

    // Force playback if the browser suspended autoplay on page load
    if (audioElementRef.current) {
      audioElementRef.current
        .play()
        .catch((e) => console.warn("Audio play blocked:", e));
    }
  };

  const stopListening = () => {
    // Tell server we left to close the PoC session
    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit("leave_broadcast");
    }
    // Do NOT null the audio stream or srcObject here.
    // We keep the audio pipeline alive so ambient audio resumes seamlessly
    // once the new upstream peer connection fires ontrack.

    if (upstreamPcRef.current) {
      upstreamPcRef.current.close();
      upstreamPcRef.current = null;
    }
    if (pendingUpstreamPcRef.current) {
      pendingUpstreamPcRef.current.close();
      pendingUpstreamPcRef.current = null;
    }

    upstreamTargetIdRef.current = null;
    setUpstreamTargetId(null);

    downstreamPcsRef.current.forEach((pc) => pc.close());
    downstreamPcsRef.current.clear();

    setStatus("AMBIENT");
    statusRef.current = "AMBIENT"; // Force immediate sync for async closures so onTrack doesn't upgrade

    if (socketRef.current?.id) {
      eventBus.emit('listener_left', { nodeId: socketRef.current.id });
    }

    // Reconnect to the mesh as an ambient observer
    if (socketRef.current && socketRef.current.connected) {
      const latentPayload = lastReportedLatentRef.current || {
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight,
        spin: Math.random(),
      };
      requestUpstreamPeer(socketRef.current, latentPayload);
    }
  };

  // Soft untune: keep the WebRTC connection alive, just toggle status.
  // The audio stream stays connected and useSpatialAudio switches to ambient filtering.
  const untuneFromBroadcast = () => {
    // Tell server we left to close the PoC session
    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit("leave_broadcast");
    }

    setStatus("AMBIENT");
    statusRef.current = "AMBIENT";
    // Clear the UI targeting — the ref keeps the real upstream peer ID
    setUpstreamTargetId(null);
    if (socketRef.current?.id) {
      eventBus.emit('listener_left', { nodeId: socketRef.current.id });
    }
  };

  return {
    status,
    activePeers,
    socketId,
    globalPeerMap,
    dataTransferRate,
    audioStream,
    upstreamTargetId,
    startListening,
    stopListening,
    untuneFromBroadcast,
  };
}

"use client";

import { useEffect, useRef, useState } from "react";
import type { ListenerStatus } from "@/lib/types";

export function useNetworkTelemetry(
    upstreamPcRef: React.MutableRefObject<RTCPeerConnection | null>,
    status: ListenerStatus
) {
    // 1.0 = Perfect. > 1.0 = High Jitter/Loss.
    const [dataTransferRate, setDataTransferRate] = useState<number>(1.0);

    // Store previous metrics to calculate precise deltas (per interval)
    const prevStatsRef = useRef({
        timestamp: 0,
        packetsReceived: 0,
        packetsLost: 0,
    });

    useEffect(() => {
        let interval: NodeJS.Timeout;

        if (status === "LISTENING") {
            // Setup polling for the WebRTC Stats
            interval = setInterval(async () => {
                const pc = upstreamPcRef.current;
                if (!pc) return;

                try {
                    const stats = await pc.getStats();
                    let inboundStats: { timestamp: number, packetsReceived?: number, packetsLost?: number, jitter?: number } | null = null;

                    // Scrape for the primary inbound RTP stream (audio route)
                    stats.forEach((report) => {
                        if (report.type === "inbound-rtp" && report.kind === "audio") {
                            inboundStats = report as { timestamp: number, packetsReceived?: number, packetsLost?: number, jitter?: number };
                        }
                    });

                    if (inboundStats) {
                        const prev = prevStatsRef.current;
                        // @ts-ignore
                        const now = inboundStats.timestamp;
                        // @ts-ignore - TS types for RTCStatsReport poorly support union properties
                        const packetsReceived = inboundStats.packetsReceived || 0;
                        // @ts-ignore
                        const packetsLost = inboundStats.packetsLost || 0;
                        // @ts-ignore
                        const jitter = inboundStats.jitter || 0; // seconds

                        // Only analyze if this isn't the first snapshot
                        if (prev.timestamp > 0 && now > prev.timestamp) {
                            const receivedDelta = packetsReceived - prev.packetsReceived;
                            const lostDelta = packetsLost - prev.packetsLost;
                            const totalDelta = receivedDelta + lostDelta;

                            let lossRatio = 0;
                            if (totalDelta > 0) {
                                lossRatio = lostDelta / totalDelta;
                            }

                            // Weighting algorithm:
                            // Baseline is 1.0 (smooth).
                            // Jitter is highly chaotic. Convert from seconds to ms (e.g. 0.05s = 50ms)
                            // Packet loss is structural. 5% loss is high impact.

                            // Normal jitter is < 0.02s. Let's scale heavily if it exceeds this.
                            const jitterStress = Math.max(0, (jitter * 1000) / 20) * 0.5;

                            // Normal loss is ~0. 5% = 0.05. Scale multiplier. 
                            const lossStress = Math.max(0, lossRatio) * 10.0;

                            const compositeStress = 1.0 + jitterStress + lossStress;

                            // We clamp it so the canvas physics don't completely explode or crash Firefox
                            const clampedStress = Math.min(5.0, compositeStress);

                            setDataTransferRate(clampedStress);
                        }

                        // Store current generation for next diff
                        prevStatsRef.current = {
                            timestamp: now,
                            packetsReceived,
                            packetsLost,
                        };
                    }
                } catch (e) {
                    console.warn("[Telemetry] Failed to gather WebRTC stats: ", e);
                }
            }, 250); // Analyze 4 times a second
        } else {
            // Reset to clean state when ambient or disconnected
            setDataTransferRate(1.0);
            prevStatsRef.current = {
                timestamp: 0,
                packetsReceived: 0,
                packetsLost: 0,
            };
        }

        return () => clearInterval(interval);
    }, [status, upstreamPcRef]);

    return { dataTransferRate };
}

"use client";

import { useEffect, useRef } from "react";
import type { SpatialData } from "../simulation/usePhysicsEngine";
import {
  MAX_AUDIO_DISTANCE,
  AMBIENT_LOWPASS_CAP,
  MIN_LOWPASS_FREQ,
  ACTIVE_LOWPASS_CAP,
} from "@/lib/physicsConstants";

export function useSpatialAudio(
  stream: MediaStream | null,
  spatialDataRef: React.MutableRefObject<SpatialData>,
) {
  const audioContextRef = useRef<AudioContext | null>(null);
  const nodesRef = useRef<{
    panner: StereoPannerNode;
    filter: BiquadFilterNode;
    masterGain: GainNode;
    source: MediaStreamAudioSourceNode | null;
  } | null>(null);

  const isInitializedRef = useRef(false);

  const initAudio = () => {
    if (isInitializedRef.current || audioContextRef.current) return;

    // Explicitly invoked by user click
    const ctx = new AudioContext();
    audioContextRef.current = ctx;

    const panner = ctx.createStereoPanner();
    const filter = ctx.createBiquadFilter();
    const masterGain = ctx.createGain();

    filter.type = "lowpass";
    filter.frequency.value = MIN_LOWPASS_FREQ;
    filter.Q.value = 1;

    panner.connect(filter);
    filter.connect(masterGain);
    masterGain.connect(ctx.destination);

    nodesRef.current = { panner, filter, masterGain, source: null };

    const updateAudioSpatial = () => {
      if (!spatialDataRef.current || !nodesRef.current) return;

      const { distanceToNode, pan, isActive, latent } = spatialDataRef.current;
      const { panner: p, filter: f, masterGain: g } = nodesRef.current;

      p.pan.setTargetAtTime(isActive ? 0 : pan, ctx.currentTime, 0.1);

      if (!isActive && (distanceToNode === Infinity || latent.x === 0)) {
        g.gain.setTargetAtTime(0.0, ctx.currentTime, 0.1);
        return;
      }

      let volume = 0;
      if (isActive) {
        volume = 1.0;
      } else {
        if (distanceToNode < 50) {
          volume = 1.0;
        } else if (distanceToNode < MAX_AUDIO_DISTANCE) {
          const normalizedDist = (distanceToNode - 50) / (MAX_AUDIO_DISTANCE - 50);
          volume = Math.pow(1.0 - normalizedDist, 2);
        } else {
          volume = 0.05;
        }
      }

      g.gain.setTargetAtTime(Math.max(0.01, volume), ctx.currentTime, 0.2);

      const maxFreq = isActive ? ACTIVE_LOWPASS_CAP : AMBIENT_LOWPASS_CAP;
      const targetFreq =
        volume === 1.0
          ? maxFreq
          : MIN_LOWPASS_FREQ + (maxFreq - MIN_LOWPASS_FREQ) * Math.pow(volume, 1.5);

      f.frequency.setTargetAtTime(targetFreq, ctx.currentTime, 0.2);
    };

    const intervalId = setInterval(updateAudioSpatial, 50);

    return () => clearInterval(intervalId);
  };

  // Clean up AudioContext strictly on unmount
  useEffect(() => {
    return () => {
      if (audioContextRef.current) {
        audioContextRef.current.close().catch(console.warn);
        audioContextRef.current = null;
      }
      nodesRef.current = null;
    }
  }, []);

  // Update MediaStream independently when it changes, avoiding suspended audio contexts
  useEffect(() => {
    if (!audioContextRef.current || !nodesRef.current) return;
    const ctx = audioContextRef.current;
    const nodes = nodesRef.current;

    // Clean up previous stream source
    if (nodes.source) {
      nodes.source.disconnect();
      nodes.source = null;
    }

    if (stream) {
      // Ensure the context is running (it may have been suspended if the
      // stream was previously null and the browser suspended the context)
      if (ctx.state === "suspended") {
        ctx.resume().catch(() => { });
      }
      nodes.source = ctx.createMediaStreamSource(stream);
      nodes.source.connect(nodes.panner);
    }
  }, [stream]);

  return {
    isInitialized: isInitializedRef.current,
    initAudio,
    resumeAudio: () => audioContextRef.current?.resume(),
  };
}

"use client";

import { useEffect, useRef } from "react";

interface AudioWaveformProps {
    stream: MediaStream | null;
}

export function AudioWaveform({ stream }: AudioWaveformProps) {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const audioCtxRef = useRef<AudioContext | null>(null);
    const analyserRef = useRef<AnalyserNode | null>(null);
    const animationIdRef = useRef<number>(0);

    useEffect(() => {
        if (!stream || !canvasRef.current) return;

        const canvas = canvasRef.current;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;

        // Initialize Audio Context if absent
        if (!audioCtxRef.current) {
            audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        }

        const audioCtx = audioCtxRef.current;
        const analyser = audioCtx.createAnalyser();
        analyser.fftSize = 256;
        analyserRef.current = analyser;

        const source = audioCtx.createMediaStreamSource(stream);
        source.connect(analyser); // We do not connect to destination (speakers) to avoid feedback

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        // Rendering Loop
        const draw = () => {
            animationIdRef.current = requestAnimationFrame(draw);

            analyser.getByteTimeDomainData(dataArray);

            // Clear background (with slight transparency for a trailing effect, optional)
            ctx.fillStyle = "rgba(0, 0, 0, 0.4)";
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.lineWidth = 1.5;
            ctx.strokeStyle = "#707070"; // highlight color from CSS array
            ctx.beginPath();

            const sliceWidth = canvas.width * 1.0 / bufferLength;
            let x = 0;

            for (let i = 0; i < bufferLength; i++) {
                const v = dataArray[i] / 128.0;
                const y = v * canvas.height / 2;

                if (i === 0) {
                    ctx.moveTo(x, y);
                } else {
                    ctx.lineTo(x, y);
                }

                x += sliceWidth;
            }

            ctx.lineTo(canvas.width, canvas.height / 2);
            ctx.stroke();
        };

        draw();

        return () => {
            cancelAnimationFrame(animationIdRef.current);
            source.disconnect();
        };
    }, [stream]);

    if (!stream) {
        return (
            <div className="w-full h-12 flex items-center justify-center border border-accent/50 bg-black/40 text-xs text-accent uppercase tracking-widest">
                [ Waiting for Signal ]
            </div>
        );
    }

    return (
        <canvas
            ref={canvasRef}
            width={400}
            height={48}
            className="w-full h-12 border border-highlight/50 bg-black/60"
        />
    );
}

import { logger } from "@/lib/logger";
// src/lib/archive/nodeAudioTransport.ts

import * as ndc from 'node-datachannel';
import { AudioTransport, TransportStats } from '@/lib/contracts';
import { persistence } from './persistenceAdapter';

/**
 * NodeJs implementation of the AudioTransport Contract.
 * Utilizes `node-datachannel` pure C++ bindings to act as a 
 * headless peer in the WebRTC mesh, strictly for archiving.
 */
export class NodeAudioTransport implements AudioTransport {
    // Map of peer connections for multi-stream archiving capability
    private connections: Map<string, ndc.PeerConnection> = new Map();

    async publish(stream: unknown): Promise<void> {
        throw new Error('NodeAudioTransport MVP only supports subscribing (recording).');
    }

    /**
     * Initializes a WebRTC connection mimicking a standard listener,
     * but explicitly capturing the Opus Media stream to the PersistenceAdapter.
     */
    async subscribe(peerId: string): Promise<any> {
        logger.info("ArchiveNode", `[ArchiveNode] Bootstrapping AudioTransport for peer: ${peerId}`);

        // We instantiate the C++ bound PeerConnection
        const pc = new ndc.PeerConnection(peerId, { iceServers: ['stun:stun.l.google.com:19302'] });
        this.connections.set(peerId, pc);

        const connectionWrapper = {
            pc,
            onLocalSignal: null as ((signal: any) => void) | null,
            initiateOffer: () => {
                // To force node-datachannel to generate an offer without tracks, we create a dummy channel
                pc.createDataChannel('ghost-layer-control');
                pc.setLocalDescription();
            },
            handleRemoteSignal: (signal: any) => {
                try {
                    if (signal.type === 'answer' || signal.type === 'offer') {
                        pc.setRemoteDescription(signal.sdp, signal.type);
                    } else if (signal.type === 'candidate' && signal.candidate) {
                        pc.addRemoteCandidate(signal.candidate.candidate, signal.candidate.sdpMid || '');
                    }
                } catch (e) {
                    console.error("[ArchiveNode] Error handling remote signal:", e);
                }
            }
        };

        pc.onLocalDescription((sdp: string, type: string) => {
            if (connectionWrapper.onLocalSignal) {
                connectionWrapper.onLocalSignal({ type, sdp });
            }
        });

        pc.onLocalCandidate((candidate: string, mid: string) => {
            if (connectionWrapper.onLocalSignal) {
                connectionWrapper.onLocalSignal({ candidate, sdpMid: mid, sdpMLineIndex: 0 }); // node-datachannel doesn't map mline index well, but this works for MVP
            }
        });

        let totalBytesReceived = 0;

        pc.onTrack((track) => {
            logger.info("ArchiveNode", `[ArchiveNode] Audio Track acquired from ${peerId}`);

            let chunkSequence = 0;
            let currentBuffer: Buffer[] = [];
            let byteCount = 0;

            // We chunk the IPFS .ogg file every ~1 megabyte for decentralized storage efficiency
            const CHUNK_SIZE_BYTES = 1048576;

            // Hook into the native C++ Media packets
            // Note: Cast to any as @types/node-datachannel varies on Media stream typings
            if (typeof (track as any).onMessage === 'function') {
                (track as any).onMessage((msg: Uint8Array | Buffer | string) => {
                    if (Buffer.isBuffer(msg) || msg instanceof Uint8Array) {
                        const buf = Buffer.from(msg);
                        currentBuffer.push(buf);
                        byteCount += buf.length;
                        totalBytesReceived += buf.length;

                        if (byteCount >= CHUNK_SIZE_BYTES) {
                            const fullChunk = Buffer.concat(currentBuffer);

                            // Contract boundary: Hand off to PersistenceAdapter
                            persistence.storeArchive(
                                fullChunk.buffer.slice(fullChunk.byteOffset, fullChunk.byteOffset + fullChunk.byteLength) as ArrayBuffer,
                                peerId,
                                chunkSequence++
                            );

                            currentBuffer = [];
                            byteCount = 0;
                        }
                    }
                });
            }
        });

        // Provide the peer connection out to the Signaling wrapper
        return connectionWrapper;
    }

    disconnect(peerId: string): void {
        const pc = this.connections.get(peerId);
        if (pc) {
            pc.close();
            this.connections.delete(peerId);
            logger.info("ArchiveNode", `[ArchiveNode] Disconnected AudioTransport for ${peerId}`);
        }
    }

    getStats(): TransportStats {
        // Returning dummy MVP stats. 
        // In production, ndc.PeerConnection exposes bytesReceived, rtt, etc.
        return {
            latency: 0,
            bytesReceived: Array.from(this.connections.values()).reduce((acc, pc) => acc + (pc.bytesReceived?.() || 0), 0),
            bytesSent: 0,
            packetsLost: 0
        };
    }
}

export const archiveTransport = new NodeAudioTransport();
